import React, { useEffect, useState, useRef, useMemo, useCallback } from 'react';
import {
    Grid, Card, CardContent, Typography, Alert, Box,
    Divider, Table, TableHead, TableRow, TableCell,
    TableBody, Chip, Skeleton, LinearProgress
} from '@mui/material';

import api from '../../services/api';
import MapView from '../../components/MapView';
import DistanceChart from '../../components/DistanceChart';
import { useAuth } from '../../contexts/AuthContext';
import PunchButton from '../../components/Punch/PunchButton';

const EmployeeDashboard = () => {

    const { user } = useAuth();

    const [data, setData] = useState({});
    const [punches, setPunches] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    const intervalRef = useRef(null);

    // ================= HELPERS =================
    const safe = (v) => Number(v) || 0;
    const safeDistance = (v) => (v ? Number(v).toFixed(2) : "0.00");

    // ================= FETCH =================
    const fetchData = useCallback(async () => {
        try {
            const [summary, punchData] = await Promise.all([
                api.getDailySummary(),
                api.getTodayPunches()
            ]);

            setData(summary?.data || {});

            const sortedPunches = (punchData?.data?.results || punchData?.data || [])
                .sort((a, b) => new Date(b.punched_at) - new Date(a.punched_at));

            setPunches(sortedPunches);

        } catch (err) {
            console.error(err);
            setError('Failed to load dashboard');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchData();

        intervalRef.current = setInterval(fetchData, 30000);
        return () => clearInterval(intervalRef.current);
    }, [fetchData]);

    // ================= KPI =================
    const kpi = useMemo(() => ({
        punchCount: safe(data?.punch_count),
        distance: safeDistance(data?.total_distance_today),
        duration: data?.duration || '--',
        collection: safeDistance(data?.total_collection),
    }), [data]);

    // ================= PRODUCTIVITY =================
    const productivity = Math.min(
        100,
        (kpi.punchCount * 10 + Number(kpi.distance)) / 2
    );

    // ================= DUMMY CHART =================
    const chartData = data?.weekly_data?.length
        ? data.weekly_data
        : [
            { day: 'Mon', distance: 5 },
            { day: 'Tue', distance: 8 },
            { day: 'Wed', distance: 6 },
            { day: 'Thu', distance: 10 },
            { day: 'Fri', distance: 7 }
        ];

    // ================= INSIGHTS =================
    const insights = [
        kpi.punchCount === 0 && "⚠ No punches recorded today",
        Number(kpi.distance) < 5 && "⚠ Low movement detected",
        Number(kpi.distance) > 10 && "🚀 Great field activity today",
        punches.length > 5 && "📈 High activity detected"
    ].filter(Boolean);

    // ================= LATEST =================
    const latestPunches = punches.slice(0, 8);

    return (
        <Box sx={{ p: 3 }}>

            {error && <Alert severity="error">{error}</Alert>}

            {/* HEADER */}
            <Box sx={{ mb: 3 }}>
                <Typography variant="h5">
                    {user?.first_name} {user?.last_name}
                </Typography>
                <Typography color="text.secondary">
                    Employee ID: {user?.employee_id}
                </Typography>
            </Box>

            {/* PUNCH */}
            <Card sx={{ mb: 3 }}>
                <CardContent sx={{ textAlign: 'center' }}>
                    <Typography variant="h6">Punch Action</Typography>
                    <PunchButton />
                </CardContent>
            </Card>

            {/* KPI */}
            <Grid container spacing={3}>
                {[
                    { label: 'Punch Count', value: kpi.punchCount },
                    { label: 'Distance', value: `${kpi.distance} km` },
                    { label: 'Working Time', value: kpi.duration },
                    { label: 'Collection', value: `₹ ${kpi.collection}` }
                ].map((item, i) => (
                    <Grid item xs={6} md={3} key={i}>
                        <Card>
                            <CardContent>
                                <Typography>{item.label}</Typography>
                                {loading
                                    ? <Skeleton width={80} />
                                    : <Typography variant="h6">{item.value}</Typography>}
                            </CardContent>
                        </Card>
                    </Grid>
                ))}

                {/* PRODUCTIVITY */}
                <Grid item xs={12} md={6}>
                    <Card>
                        <CardContent>
                            <Typography variant="h6">Productivity Score</Typography>
                            <LinearProgress
                                variant="determinate"
                                value={productivity}
                                sx={{ height: 10, borderRadius: 5, mt: 2 }}
                            />
                            <Typography sx={{ mt: 1 }}>
                                {productivity.toFixed(0)}%
                            </Typography>
                        </CardContent>
                    </Card>
                </Grid>

                {/* INSIGHTS */}
                <Grid item xs={12} md={6}>
                    <Card>
                        <CardContent>
                            <Typography variant="h6">Insights</Typography>
                            {insights.length === 0 ? (
                                <Typography>No insights</Typography>
                            ) : insights.map((i, idx) => (
                                <Typography key={idx}>• {i}</Typography>
                            ))}
                        </CardContent>
                    </Card>
                </Grid>

                {/* CHART */}
                <Grid item xs={12} md={6}>
                    <Card>
                        <CardContent>
                            <Typography variant="h6">Weekly Distance</Typography>
                            {loading
                                ? <Skeleton height={200} />
                                : <DistanceChart data={chartData} />}
                        </CardContent>
                    </Card>
                </Grid>

                {/* MAP */}
                <Grid item xs={12} md={6}>
                    <Card>
                        <CardContent>
                            <Typography variant="h6">Live Map</Typography>
                            {loading
                                ? <Skeleton height={200} />
                                : <MapView punches={punches} />}
                        </CardContent>
                    </Card>
                </Grid>
            </Grid>

            {/* ACTIVITY */}
            <Card sx={{ mt: 3 }}>
                <CardContent>
                    <Typography variant="h6">Today Activity</Typography>
                    <Divider sx={{ my: 2 }} />

                    {loading ? (
                        <Skeleton height={200} />
                    ) : latestPunches.length === 0 ? (
                        <Alert severity="info">No activity yet</Alert>
                    ) : (
                        <Table size="small">
                            <TableHead>
                                <TableRow>
                                    <TableCell>#</TableCell>
                                    <TableCell>Type</TableCell>
                                    <TableCell>Time</TableCell>
                                    <TableCell>Location</TableCell>
                                    <TableCell>Distance</TableCell>
                                </TableRow>
                            </TableHead>

                            <TableBody>
                                {latestPunches.map((p, i) => (
                                    <TableRow key={i}>
                                        <TableCell>{i + 1}</TableCell>

                                        <TableCell>
                                            <Chip
                                                label={p.punch_type}
                                                color={
                                                    p.punch_type === 'PUNCH_IN'
                                                        ? 'success'
                                                        : 'primary'
                                                }
                                                size="small"
                                            />
                                        </TableCell>

                                        <TableCell>
                                            {new Date(p.punched_at).toLocaleTimeString()}
                                        </TableCell>

                                        <TableCell>
                                            {p.latitude
                                                ? `${Number(p.latitude).toFixed(4)}, ${Number(p.longitude).toFixed(4)}`
                                                : 'No location'}
                                        </TableCell>

                                        <TableCell>
                                            {safeDistance(p.distance_from_last)} km
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    )}
                </CardContent>
            </Card>

        </Box>
    );

};

export default React.memo(EmployeeDashboard);